user.name = 'Pete' // shows "SET name=Pete"`},{header:"reflect",slug:"reflect",content:"const z = { w: `Super Hello` }\nconst y = { x: `hello`, __proto__: z } console.log(Reflect.getOwnPropertyDescriptor(y, `x`))\nconsole.log(Reflect.has(y, `w`))\nconsole.log(Reflect.ownKeys(y, `w`)) console.log(Reflect.has(y, `x`))\nconsole.log(Reflect.deleteProperty(y, `x`))\nconsole.log(Reflect.has(y, `x`))\n{ console.log(`________________________________________________`) const obj = new Proxy( {}, { get(target, key, receiver) { console.log(`getting ${key}!`) return Reflect.get(target, key, receiver) }, set(target, key, value, receiver) { console.log(`setting ${key}!`) return Reflect.set(target, key, value, receiver) }, } )\n} { console.log(`________________________________________________`) const handler = { get: (target, name) => (name in target ? target[name] : 29), } const p = new Proxy({}, handler) p.a = 1 p.b = undefined console.log(`c` in p, p.c)\n}"},{header:"get\u548Cset",slug:"get\u548Cset",content:`const data = [1, 2, 3]
